INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-64311456-moex-00107', 'retired-64311456', 'retired-64311456-moex-112-13504c0c', 'sub-retired-64311456-01', NULL, 'single_choice', '「高音的條件，是要有寬厚充足的氣力，讓聲音上去，有飽滿的氣力來襯托，才不 會高而危薄，終不能長久。」 下列選項，何者最切合文中所表達的旨趣？', '["為高必因丘陵，為下必因川澤", "無為其所不為，無欲其所不欲", "水之積也不厚，則其負大舟也無力", "致廣大而盡精微，極高明而道中庸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00108', 'retired-64311456', 'retired-64311456-moex-112-13504c0c', 'sub-retired-64311456-01', NULL, 'single_choice', '「日本著名導演黑澤明的自傳用了一個奇怪的書名：《蝦蟆的油》。它來自日本的 一則民間傳說：有位醫生抓到一隻醜陋的蝦蟆，牠長有四隻前腳、六隻後腳。醫生 將蝦蟆裝進一個玻璃箱內，蝦蟆從鏡面的玻璃中，第一次看到自己醜陋的形象，嚇 得擠出一身油來。醫生收取這些油，用來治療病人的燒燙割傷，據說具有奇效。」 根據上文，下列何者最符合黑澤明傳記的命名旨趣？', '["作者自覺一生失敗難堪，猶如醜陋的蝦蟆，自慚形穢", "人世的險惡如醜陋的蝦蟆，令人驚駭莫名，細思極恐", "作者反思醜陋難堪的過往，透過書寫傳記以療傷止痛", "作者揭示自身難堪的經歷，盼能醫治讀者心靈的傷痛"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00109', 'retired-64311456', 'retired-64311456-moex-112-13504c0c', 'sub-retired-64311456-01', NULL, 'single_choice', '「紐曼認為大學是一個提供博雅教育，培育紳士的地方（雖然他也認為大學可以訓 練職業人才），他以為大學之目的在『傳授』學問而不在『發展』知識。他說：『如 果大學的目的在科學的與哲學的發明，那麼，我看不出為什麼大學應該有學生。』 紐曼之書為論大學之經典。他心中大學所應培育之紳士乃指通達而有修養與識見之 文化人。」 根據上文，最符合文中旨意的選項是：', '["大學最重要的目的在培育有創見的學者", "大學應以學生為重，提供優良博雅教育", "大學應該積極作為訓練職業人才的地方", "科學的與哲學的發明，是大學重要目的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00110', 'retired-64311456', 'retired-64311456-moex-112-13504c0c', 'sub-retired-64311456-01', NULL, 'single_choice', '「2006年3月，設計博物館與BBC舉辦大眾票選，尋找英國最愛的設計符碼，紅 色電話亭名列前茅。儘管如今它幾乎失去了原有的功能，它的歷史、設計與過往日 常生活中的地位，也使它優雅地成為英國的國家象徵，也是公共性的體現。或許在 不久的將來，紅色電話亭也會跟文書軟體上代表儲存的磁碟片圖示一樣，晦澀而遙 遠。儘管原有的功能已成歷史，然而在符碼再次轉化與詮釋的過程中，似乎還是可 以發揮新意，這點也很英國。」 根據上文，「這點也很英國」的看法，下列選項何者正確？', '["希望能在保留傳統的同時，也發展出新的創見和意涵", "偏愛晦澀且遙遠的事物，因此希望保留古老的紅色電話亭", "強調優雅與日常，而紅色電話亭的設計正是符合這樣的要求", "重視傳統與科技的平衡，希望將傳統的文化以新興的科技保存下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00111', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '1 考 試 別：一般警察人員考試、鐵路人員考試、退除役軍人轉任公務人員考試 類科組別：各類別、各類科', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00112', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '有關法治國原則，下列敘述何者正確？', '["大法官迄今尚未承認法治國原則為我國憲法基本原則", "地方政府限制人民之自由權利，若屬地方自治事項，即無法治國原則之適用", "法治國原則要求，立法者制定法律時，不得在法律中使用不確定法律概念", "司法機關行使司法權，亦受法治國原則拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00113', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '下列何種事項，憲法或增修條文並無明文規定以法律定之？', '["外交", "創制、複決兩權之行使", "國防之組織", "原住民族之地位及政治參與"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00114', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '依司法院大法官解釋，關於人民應考試服公職之權，下列敘述何者錯誤？', '["應考試、服公職分別為兩種權利", "應考試服公職之權為廣義之參政權", "專門職業及技術人員因非公務人員，其應考試權不受憲法保障", "人民服公職之權受侵害，得提起行政爭訟以為救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00115', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '集會遊行法第8條規定，室外集會、遊行，應向主管機關申請許可。但宗教、民俗、婚、喪、喜、慶活動 等不在此限，不涉及下列何種基本權利？', '["集會自由", "信仰自由", "宗教自由", "遷徙自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL),
  ('retired-64311456-moex-00116', 'retired-64311456', 'retired-64311456-moex-112-3d2b73b6', 'sub-retired-64311456-02', NULL, 'single_choice', '依司法院大法官解釋意旨，有關徵收補償，下列敘述何者錯誤？', '["徵收之補償應儘速發給，否則徵收土地核准案即應失其效力", "直轄市或縣（市）政府事後發現原發給之補償費短少，得自由裁量是否撤銷原補償處分", "補償應合理、相當", "區段徵收制度中，以徵收後可供建築之抵價地折算抵付補償費，屬徵收補償方式之一種"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:15+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "132", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會行政"}'::jsonb, NULL)
